export const EXERCISE_SEED_DATA: ExerciseRow[] = DATA.map((e, i) => ({
  ...e,
  topRated: e.topRated ?? false,
  sortOrder: i,
}));

/** Ensure the exercises table exists and is seeded. Self-contained — no migration dependency. */
export async function seedExercises(database: DB): Promise<void> {
  // Create table if it doesn't exist yet (idempotent — safe to call on every startup)
  await database.execute(sql`
    CREATE TABLE IF NOT EXISTS exercises (
      id          text      PRIMARY KEY NOT NULL,
      name        text      NOT NULL,
      muscle_groups text[]  DEFAULT '{}' NOT NULL,
      category    text      NOT NULL,
      "group"     text      NOT NULL,
      top_rated   boolean   DEFAULT false NOT NULL,
      sort_order  integer   DEFAULT 0 NOT NULL
    )
  `);

  // Only insert if table is empty
  const existing = await database.select({ id: exercises.id }).from(exercises).limit(1);
  if (existing.length > 0) return;

  console.log(`Seeding ${EXERCISE_SEED_DATA.length} exercises...`);
  const BATCH = 50;
  for (let i = 0; i < EXERCISE_SEED_DATA.length; i += BATCH) {
    await database.insert(exercises).values(EXERCISE_SEED_DATA.slice(i, i + BATCH));
  }
  console.log('Exercise seed complete.');
}
